const request = $json.body ?? $json;
const headers = $json.headers ?? {};
const expectedSecret = String($env.N8N_WHATSAPP_ROUTER_SECRET || '').trim();
const incomingSecret = String(headers['x-quicreply-webhook-secret'] || headers['X-Quicreply-Webhook-Secret'] || '').trim();

if (!expectedSecret || incomingSecret !== expectedSecret) {
  throw new Error('Unauthorized QuicReply inbox webhook request.');
}

if (request.event === 'runtime.health') {
  return [{ json: { mode: 'health' } }];
}

const organizationId = String(request.organizationId || '').trim();
const contactId = String(request.contactId || '').trim();
const providerMessageId = String(request.message?.id || '').trim();
const customerMessage = String(request.message?.text || '').trim();
const callbackUrl = String(request.callback?.replyUrl || '').trim();
const phone = String(request.contact?.phone || request.phone || '').trim();

if (!organizationId || !contactId || !providerMessageId || !customerMessage || !callbackUrl || !phone) {
  throw new Error('Incomplete QuicReply inbox payload.');
}

let forcedAction = null;
let forcedReason = null;
let forcedCategory = null;
if (request.organization?.isAiActive !== true || request.contact?.isAiActive !== true) {
  forcedAction = 'skip';
  forcedReason = 'Jennifer is disabled for this workspace or contact.';
  forcedCategory = 'ai_disabled';
} else if (['human-active', 'needs-attention', 'resolved'].includes(String(request.thread?.state || ''))) {
  forcedAction = 'skip';
  forcedReason = `Thread state does not allow AI replies: ${request.thread.state}.`;
  forcedCategory = 'thread_not_ai_active';
} else {
  const handoffRules = [
    [/\b(human|person|agent|representative|manager|someone real)\b/i, 'human_request'],
    [/\b(refund|chargeback|billing dispute|charged twice|unauthori[sz]ed charge)\b/i, 'billing_or_refund'],
    [/\b(lawyer|legal|lawsuit|regulator|compliance|police)\b/i, 'legal_or_compliance'],
    [/\b(order status|where is my order|tracking number|payment status)\b/i, 'account_specific_status'],
    [/\b(angry|furious|scam|fraud|terrible service|unacceptable)\b/i, 'customer_escalation'],
    [/\b(custom price|special price|negotiate|bulk discount)\b/i, 'commercial_negotiation']
  ];
  const matchedRule = handoffRules.find(([pattern]) => pattern.test(customerMessage));
  if (matchedRule) {
    forcedAction = 'handoff';
    forcedReason = 'This request requires human review.';
    forcedCategory = matchedRule[1];
  }
}

const history = Array.isArray(request.thread?.recentMessages) ? request.thread.recentMessages : [];
const compactHistory = history.slice(-12).map((entry) => `${entry.role === 'assistant' ? 'Jennifer' : 'Customer'}: ${String(entry.text || '').trim()}`).filter((entry) => !entry.endsWith(': '));
const knowledge = request.aiKnowledge || {};
const context = request.businessContext || {};

const prompt = [
  'You are Jennifer, the live WhatsApp assistant for this business.',
  'Write only the customer-facing reply text.',
  'Use only the supplied business facts and conversation history.',
  'Never claim a refund, payment, order change, delivery, account update, or other live action happened unless the supplied context confirms it.',
  'Do not invent prices, stock, order status, discounts, guarantees, or policies.',
  'Keep the reply concise and ask at most one follow-up question.',
  `Business: ${String(context.businessDescription || 'Not provided.')}`,
  `Products and services: ${String(context.productsServices || 'Not provided.')}`,
  `First-message guidance: ${String(context.firstAiMessage || 'Not provided.')}`,
  `Response style: ${String(context.responseStyle || 'professional')}`,
  `Language: ${String(context.aiLanguage || 'English')}`,
  `Pricing and plans: ${String(knowledge.pricingAndPlans || 'Not provided.')}`,
  `Seats and limits: ${String(knowledge.seatsAndLimits || 'Not provided.')}`,
  `Core features: ${String(knowledge.coreFeatures || 'Not provided.')}`,
  `Product pages: ${String(knowledge.productPages || 'Not provided.')}`,
  `Policies and FAQs: ${String(knowledge.policiesAndFaqs || 'Not provided.')}`,
  `Conversation:\n${compactHistory.length ? compactHistory.join('\n') : 'No earlier messages.'}`,
  `Latest customer message: ${customerMessage}`
].join('\n');

return [{ json: { mode: 'message', organizationId, contactId, providerMessageId, callbackUrl, phone, forcedAction, forcedReason, forcedCategory, openclawPrompt: prompt } }];

let action = $json.forcedAction;
let message = '';
let confidence = 0;
let reason = $json.forcedReason;
let handoffCategory = $json.forcedCategory;

if (!action) {
  if ($json.error) {
    action = 'handoff';
    reason = 'Jennifer runtime was unavailable while processing this message.';
    handoffCategory = 'runtime_unavailable';
    console.error(JSON.stringify({ event: 'openclaw_failure', organizationId: $json.organizationId, contactId: $json.contactId, providerMessageId: $json.providerMessageId }));
  } else {
    const output = Array.isArray($json.output) ? $json.output : [];
    const text = output.flatMap((entry) => Array.isArray(entry.content) ? entry.content : []).find((entry) => entry?.type === 'output_text' && typeof entry.text === 'string')?.text?.trim();
    if (!text || text.startsWith('```') || text.includes('<tool')) {
      action = 'handoff';
      reason = 'Jennifer returned an invalid response.';
      handoffCategory = 'invalid_runtime_output';
    } else {
      action = 'reply';
      message = text;
      confidence = 0.7;
      reason = 'Safe response generated from the saved business context.';
    }
  }
}

return [{ json: { callbackUrl: $json.callbackUrl, organizationId: $json.organizationId, contactId: $json.contactId, providerMessageId: $json.providerMessageId, to: $json.phone, action, message, confidence, reason, handoffCategory } }];
